              "options": {
                "key": {
                  "$key": true
                }
              }
            },
            {
              "names": [
                "password"
              ],
              "options": {
                "prefix": "crypted_",
                "suffix": "_test"
              }
            },
            {
              "names": [
                "ssn"
              ],
              "options": {
                "key": {
                  "$key": true
                },
                "attribute": "ssn_encrypted"
              }
