  "cases": [
    {
      "input": {
        "model": {
          "attributes": [
            {
              "names": [
                "email"
              ],
              "options": {
                "key": {
                  "$key": true
                }
              }
            }
          ],
          "global_options": {
            "key": {
              "$proc_key": true
            },
            "mode": "per_attribute_iv_and_salt"
          }
        },
        "ops": [
          {
            "kind": "assign_read",
            "attr": "email",
            "value": "test@example.com",
            "report_stored": true,
            "report_stored_equals_plain": true
          }
        ]
      },
      "expected_output": "assign_read[email]=test@example.com\nstored_equals_plain[email]=false\nstored_present[email]=true\n"
    },
    {
      "input": {
        "model": {
          "attributes": [
            {
              "names": [
                "email"
              ],
              "options": {
                "key": {
                  "$key": true
                }
              }
            }
          ],
          "global_options": {
            "key": {
              "$proc_key": true
            },
            "mode": "per_attribute_iv_and_salt"
          }
        },
        "ops": [
          {
            "kind": "predicate_steps",
            "attr": "email",
            "steps": [
              {
                "assign": false
              },
              {
                "assign": true,
                "value": ""
              },
              {
                "assign": true,
                "value": "test@example.com"
